#!/bin/bash\n\n# Container Management Script for TikTok Clone\n# Provides comprehensive Docker Compose operations\n\nset -e\n\n# Colors for output\nRED='\\033[0;31m'\nGREEN='\\033[0;32m'\nYELLOW='\\033[1;33m'\nBLUE='\\033[0;34m'\nNC='\\033[0m' # No Color\n\nDOCKER_COMPOSE=\"docker-compose\"\nPROJECT_NAME=\"tiktok-clone\"\nENV_FILE=\".env\"\n\n# Help function\nshow_help() {\n    cat << EOF\nTikTok Clone Container Management\n\nUsage: $0 [COMMAND] [OPTIONS]\n\nCommands:\n    up              Start all containers\n    down            Stop all containers\n    ps              Show running containers\n    logs            Show container logs\n    logs-follow     Follow container logs (real-time)\n    build           Build Docker images\n    rebuild         Rebuild all images\n    pull            Pull latest base images\n    shell           Open shell in a container\n    exec            Execute command in running container\n    restart         Restart containers\n    status          Show container status and health\n    clean           Remove all containers and volumes\n    prune           Remove unused Docker resources\n    backup          Backup database\n    restore         Restore database from backup\n    test            Run tests in containers\n    monitor         Open monitoring dashboards\n    scale           Scale services\n    update          Update running containers\n    stats           Show container resource usage\n    health-check    Run health checks on all services\n\nExamples:\n    $0 up                          # Start all services\n    $0 logs -f server              # Follow server logs\n    $0 shell postgres              # Connect to PostgreSQL\n    $0 status                      # Check all service health\n    $0 backup                      # Backup database\n    $0 scale server=3              # Scale server to 3 replicas\n\nEOF\n}\n\n# Check Docker installation\ncheck_docker() {\n    if ! command -v docker &> /dev/null; then\n        echo -e \"${RED}Error: Docker is not installed${NC}\"\n        exit 1\n    fi\n    if ! command -v docker-compose &> /dev/null; then\n        echo -e \"${RED}Error: Docker Compose is not installed${NC}\"\n        exit 1\n    fi\n}\n\n# Load environment variables\nload_env() {\n    if [ -f \"$ENV_FILE\" ]; then\n        export $(cat \"$ENV_FILE\" | grep -v '^#' | xargs)\n    fi\n}\n\n# Start containers\nup() {\n    echo -e \"${BLUE}Starting TikTok Clone containers...${NC}\"\n    $DOCKER_COMPOSE -p $PROJECT_NAME up -d\n    echo -e \"${GREEN}Containers started successfully!${NC}\"\n    sleep 3\n    status\n}\n\n# Stop containers\ndown() {\n    echo -e \"${BLUE}Stopping TikTok Clone containers...${NC}\"\n    $DOCKER_COMPOSE -p $PROJECT_NAME down\n    echo -e \"${GREEN}Containers stopped${NC}\"\n}\n\n# Show running containers\nps_containers() {\n    $DOCKER_COMPOSE -p $PROJECT_NAME ps\n}\n\n# Show logs\nshow_logs() {\n    local service=$1\n    local follow=$2\n    if [ -z \"$service\" ]; then\n        service=$(docker ps --format \"table {{.Names}}\" | grep $PROJECT_NAME | head -1)\n    fi\n    if [ \"$follow\" = \"--follow\" ] || [ \"$follow\" = \"-f\" ]; then\n        $DOCKER_COMPOSE -p $PROJECT_NAME logs -f $service\n    else\n        $DOCKER_COMPOSE -p $PROJECT_NAME logs $service\n    fi\n}\n\n# Build images\nbuild_images() {\n    echo -e \"${BLUE}Building Docker images...${NC}\"\n    $DOCKER_COMPOSE -p $PROJECT_NAME build\n    echo -e \"${GREEN}Images built successfully!${NC}\"\n}\n\n# Rebuild images (no cache)\nrebuild_images() {\n    echo -e \"${BLUE}Rebuilding Docker images (no cache)...${NC}\"\n    $DOCKER_COMPOSE -p $PROJECT_NAME build --no-cache\n    echo -e \"${GREEN}Images rebuilt successfully!${NC}\"\n}\n\n# Pull base images\npull_images() {\n    echo -e \"${BLUE}Pulling latest base images...${NC}\"\n    docker pull postgres:15-alpine\n    docker pull redis:7-alpine\n    docker pull ipfs/go-ipfs:v0.17.0\n    docker pull minio/minio:latest\n    docker pull nginx:alpine\n    docker pull prom/prometheus:latest\n    docker pull docker.elastic.co/elasticsearch/elasticsearch:8.5.0\n    docker pull node:18-alpine\n    echo -e \"${GREEN}Images pulled successfully!${NC}\"\n}\n\n# Shell access\nshell_access() {\n    local service=$1\n    if [ -z \"$service\" ]; then\n        echo -e \"${RED}Error: Please specify service name${NC}\"\n        echo \"Available services: postgres, redis, ipfs, minio, server, nginx\"\n        exit 1\n    fi\n    echo -e \"${BLUE}Opening shell in $service...${NC}\"\n    $DOCKER_COMPOSE -p $PROJECT_NAME exec $service /bin/sh 2>/dev/null || \\\n    $DOCKER_COMPOSE -p $PROJECT_NAME exec $service /bin/bash 2>/dev/null || \\\n    $DOCKER_COMPOSE -p $PROJECT_NAME exec $service psql -U ${DB_USER:-user} -d tiktok-clone\n}\n\n# Execute command\nexec_command() {\n    local service=$1\n    shift\n    local cmd=$@\n    if [ -z \"$service\" ]; then\n        echo -e \"${RED}Error: Please specify service name${NC}\"\n        exit 1\n    fi\n    echo -e \"${BLUE}Executing in $service: $cmd${NC}\"\n    $DOCKER_COMPOSE -p $PROJECT_NAME exec -T $service $cmd\n}\n\n# Restart containers\nrestart_containers() {\n    local service=$1\n    if [ -z \"$service\" ]; then\n        echo -e \"${BLUE}Restarting all services...${NC}\"\n        $DOCKER_COMPOSE -p $PROJECT_NAME restart\n    else\n        echo -e \"${BLUE}Restarting $service...${NC}\"\n        $DOCKER_COMPOSE -p $PROJECT_NAME restart $service\n    fi\n    echo -e \"${GREEN}Restart complete${NC}\"\n}\n\n# Container status\nstatus() {\n    echo -e \"${BLUE}=== TikTok Clone Container Status ===${NC}\"\n    echo \"\"\n    \n    # Check each service\n    services=(\"postgres\" \"redis\" \"ipfs\" \"minio\" \"server\" \"nginx\")\n    \n    for service in \"${services[@]}\"; do\n        container_name=\"${PROJECT_NAME}-${service}\"\n        if docker ps --filter \"name=$container_name\" --format '{{.Names}}' | grep -q .; then\n            status=$(docker inspect -f '{{.State.Status}}' \"${PROJECT_NAME}_${service}_1\" 2>/dev/null || echo \"unknown\")\n            health=$(docker inspect -f '{{.State.Health.Status}}' \"${PROJECT_NAME}_${service}_1\" 2>/dev/null || echo \"N/A\")\n            \n            if [ \"$status\" = \"running\" ]; then\n                status_icon=\"✓\"\n                status_color=\"${GREEN}\"\n            else\n                status_icon=\"✗\"\n                status_color=\"${RED}\"\n            fi\n            \n            printf \"${status_color}%s${NC} %-12s Status: %-10s Health: %s\\n\" \"$status_icon\" \"$service\" \"$status\" \"$health\"\n        else\n            printf \"${RED}✗${NC} %-12s ${RED}Not running${NC}\\n\" \"$service\"\n        fi\n    done\n    \n    echo \"\"\n    echo -e \"${BLUE}Docker Compose Project: $PROJECT_NAME${NC}\"\n}\n\n# Clean all\nclean() {\n    echo -e \"${YELLOW}WARNING: This will remove all containers and volumes!${NC}\"\n    read -p \"Continue? (yes/no): \" confirm\n    if [ \"$confirm\" = \"yes\" ]; then\n        echo -e \"${BLUE}Cleaning up...${NC}\"\n        $DOCKER_COMPOSE -p $PROJECT_NAME down -v\n        echo -e \"${GREEN}Cleanup complete${NC}\"\n    else\n        echo \"Cancelled\"\n    fi\n}\n\n# Prune unused resources\nprune() {\n    echo -e \"${YELLOW}Pruning unused Docker resources...${NC}\"\n    docker system prune -f\n    echo -e \"${GREEN}Prune complete${NC}\"\n}\n\n# Backup database\nbackup_database() {\n    local timestamp=$(date +%Y%m%d_%H%M%S)\n    local backup_file=\"backups/tiktok-db-${timestamp}.sql\"\n    \n    mkdir -p backups\n    \n    echo -e \"${BLUE}Backing up database to $backup_file...${NC}\"\n    $DOCKER_COMPOSE -p $PROJECT_NAME exec -T postgres pg_dump -U ${DB_USER:-user} -d tiktok-clone > \"$backup_file\"\n    echo -e \"${GREEN}Backup complete: $backup_file${NC}\"\n}\n\n# Restore database\nrestore_database() {\n    local backup_file=$1\n    if [ -z \"$backup_file\" ]; then\n        echo -e \"${RED}Error: Please specify backup file${NC}\"\n        exit 1\n    fi\n    if [ ! -f \"$backup_file\" ]; then\n        echo -e \"${RED}Error: Backup file not found: $backup_file${NC}\"\n        exit 1\n    fi\n    \n    echo -e \"${YELLOW}WARNING: This will overwrite the current database!${NC}\"\n    read -p \"Continue? (yes/no): \" confirm\n    if [ \"$confirm\" = \"yes\" ]; then\n        echo -e \"${BLUE}Restoring database from $backup_file...${NC}\"\n        $DOCKER_COMPOSE -p $PROJECT_NAME exec -T postgres psql -U ${DB_USER:-user} -d tiktok-clone < \"$backup_file\"\n        echo -e \"${GREEN}Restore complete${NC}\"\n    else\n        echo \"Cancelled\"\n    fi\n}\n\n# Monitor dashboards\nmonitor() {\n    echo -e \"${BLUE}Opening monitoring dashboards...${NC}\"\n    echo \"\"\n    echo \"Prometheus:     http://localhost:9090\"\n    echo \"Elasticsearch:  http://localhost:9200\"\n    echo \"MinIO Console:  http://localhost:9001 (admin/minioadmin123)\"\n    echo \"IPFS WebUI:     http://localhost:5001/webui\"\n    echo \"API Health:     http://localhost:5000/health\"\n    echo \"\"\n}\n\n# Scale services\nscale_service() {\n    local service_scale=$1\n    if [ -z \"$service_scale\" ]; then\n        echo -e \"${RED}Error: Please specify service scaling (e.g., server=3)${NC}\"\n        exit 1\n    fi\n    echo -e \"${BLUE}Scaling: $service_scale${NC}\"\n    $DOCKER_COMPOSE -p $PROJECT_NAME up -d --scale $service_scale\n    echo -e \"${GREEN}Scaling complete${NC}\"\n    status\n}\n\n# Container stats\nshow_stats() {\n    echo -e \"${BLUE}=== Container Resource Usage ===${NC}\"\n    docker stats --no-stream --format \"table {{.Container}}\\t{{.CPUPerc}}\\t{{.MemUsage}}\"\n}\n\n# Health check\nhealth_check() {\n    echo -e \"${BLUE}=== Running Health Checks ===${NC}\"\n    echo \"\"\n    \n    # Check API\n    echo -n \"API Server: \"\n    if curl -s -f http://localhost:5000/health > /dev/null; then\n        echo -e \"${GREEN}✓ Healthy${NC}\"\n    else\n        echo -e \"${RED}✗ Unhealthy${NC}\"\n    fi\n    \n    # Check Database\n    echo -n \"PostgreSQL: \"\n    if $DOCKER_COMPOSE -p $PROJECT_NAME exec -T postgres pg_isready -U ${DB_USER:-user}  > /dev/null 2>&1; then\n        echo -e \"${GREEN}✓ Healthy${NC}\"\n    else\n        echo -e \"${RED}✗ Unhealthy${NC}\"\n    fi\n    \n    # Check Redis\n    echo -n \"Redis: \"\n    if $DOCKER_COMPOSE -p $PROJECT_NAME exec -T redis redis-cli ping | grep -q PONG; then\n        echo -e \"${GREEN}✓ Healthy${NC}\"\n    else\n        echo -e \"${RED}✗ Unhealthy${NC}\"\n    fi\n    \n    # Check IPFS\n    echo -n \"IPFS: \"\n    if curl -s -f http://localhost:5001/api/v0/id > /dev/null; then\n        echo -e \"${GREEN}✓ Healthy${NC}\"\n    else\n        echo -e \"${RED}✗ Unhealthy${NC}\"\n    fi\n    \n    # Check MinIO\n    echo -n \"MinIO: \"\n    if curl -s -f http://localhost:9000/minio/health/live > /dev/null; then\n        echo -e \"${GREEN}✓ Healthy${NC}\"\n    else\n        echo -e \"${RED}✗ Unhealthy${NC}\"\n    fi\n    \n    echo \"\"\n}\n\n# Main execution\ncheck_docker\nload_env\n\ncommand=$1\nshift || true\n\ncase \"$command\" in\n    up)              up ;;;\n    down)            down ;;;\n    ps)              ps_containers ;;;\n    logs)            show_logs $@ ;;;\n    logs-follow)     show_logs $1 \"--follow\" ;;;\n    build)           build_images ;;;\n    rebuild)         rebuild_images ;;;\n    pull)            pull_images ;;;\n    shell)           shell_access $@ ;;;\n    exec)            exec_command $@ ;;;\n    restart)         restart_containers $@ ;;;\n    status)          status ;;;\n    clean)           clean ;;;\n    prune)           prune ;;;\n    backup)          backup_database ;;;\n    restore)         restore_database $1 ;;;\n    monitor)         monitor ;;;\n    scale)           scale_service $1 ;;;\n    stats)           show_stats ;;;\n    health-check)   health_check ;;;\n    update)          rebuild_images && up ;;;\n    *)               show_help ;;;\nesac\n